using Microsoft.ML;

namespace ChurnPredictor;

public static class ChurnModelTrainer
{
    public static string Train(string dataPath, string modelPath)
    {
        var mlContext = new MLContext(seed: 42);

        // Load CSV and map "Yes"/"No" to boolean Label
        var rows = File.ReadLines(dataPath)
            .Skip(1) // header
            .Select(line => line.Split(','))
            .Select(cols => new CustomerData
            {
                Age = float.Parse(cols[0]),
                Income = float.Parse(cols[1]),
                Region = cols[2],
                PurchaseHistory = float.Parse(cols[3]),
                Churned = string.Equals(cols[4].Trim(), "Yes", StringComparison.OrdinalIgnoreCase)
            })
            .ToList();

        IDataView data = mlContext.Data.LoadFromEnumerable(rows);
        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Categorical
                .OneHotEncoding("RegionEncoded", "Region")
            .Append(mlContext.Transforms.Concatenate("Features",
                "Age", "Income", "RegionEncoded", "PurchaseHistory"))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(mlContext.BinaryClassification.Trainers
                .SdcaLogisticRegression(labelColumnName: "Label", featureColumnName: "Features"));

        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");

        var report = $"AUC: {metrics.AreaUnderRocCurve:F4} | " +
                     $"Accuracy: {metrics.Accuracy:F4} | " +
                     $"F1: {metrics.F1Score:F4}";

        mlContext.Model.Save(model, data.Schema, modelPath);

        return report;
    }
}

