using ChurnPredictor;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "churn-model.zip");

// Train the model at startup and log evaluation metrics
var metrics = ChurnModelTrainer.Train(dataPath, modelPath);
builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.Logger.LogInformation("Model trained — {Metrics}", metrics);

app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (CustomerInput input, PredictionEnginePool<CustomerData, ChurnPrediction> pool) =>
{
    var customerData = new CustomerData
    {
        Age = input.Age,
        Income = input.Income,
        Region = input.Region,
        PurchaseHistory = input.PurchaseHistory
    };

    var prediction = pool.Predict(customerData);

    return Results.Ok(new
    {
        willChurn = prediction.Churned,
        probability = prediction.Probability
    });
});

app.Run();

